# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, request, redirect, session, url_for
import requests
import json
import base64
import urllib.parse
import secrets
import hashlib

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# Configuration
OIDC_CONFIG = {
    'authorization_endpoint': 'https://provider.com/oauth2/v1/authorize',
    'token_endpoint': 'https://provider.com/oauth2/v1/token',
    'userinfo_endpoint': 'https://provider.com/oauth2/v1/userinfo',
    'client_id': 'your_client_id',
    'client_secret': 'your_client_secret',
    'redirect_uri': 'http://localhost:5000/callback',
    'scope': 'openid profile email'
}

def decode_jwt(token):
    header, payload, signature = token.split('.')
    payload += '=' * (4 - len(payload) % 4)
    decoded = base64.b64decode(payload)
    return json.loads(decoded)

@app.route('/')
def index():
    if 'user' in session:
        return f'Hello {session["user"]["name"]}! <a href="/logout">Logout</a>'
    return '<a href="/login">Login with OpenID Connect</a>'

@app.route('/login')
def login():
    state = secrets.token_urlsafe(32)
    session['state'] = state
    
    params = {
        'response_type': 'code',
        'client_id': OIDC_CONFIG['client_id'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'scope': OIDC_CONFIG['scope'],
        'state': state
    }
    
    auth_url = f"{OIDC_CONFIG['authorization_endpoint']}?{urllib.parse.urlencode(params)}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return f'Error: {error}'
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if state != session.get('state'):
        return 'Invalid state parameter'
    
    token_data = {
        'grant_type': 'authorization_code',
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'code': code
    }
    
    response = requests.post(OIDC_CONFIG['token_endpoint'], data=token_data)
    token_response = response.json()
    
    id_token = token_response.get('id_token')
    if not id_token:
        return 'No ID token received'
    
    user_claims = decode_jwt(id_token)
    
    session['user'] = {
        'sub': user_claims.get('sub'),
        'name': user_claims.get('name'),
        'email': user_claims.get('email'),
        'picture': user_claims.get('picture')
    }
    
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)